using System.ComponentModel;
using System.Drawing.Design;
using System.Runtime.InteropServices;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public partial class MyControl : UserControl
{
    private StatusStrip _statusStrip;
    private ToolStripStatusLabel _statusLabel;

    public string DisplayName { get; set; }

    [Editor(typeof(MaxItemsEditor), typeof(UITypeEditor))]
    public int MaxItems { get; set; }

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        _statusLabel = new ToolStripStatusLabel("Ready");

        // .NET 9: StatusStrip default renderer changed from Professional to System.
        // Explicitly set Professional to preserve the .NET 8 visual appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.Professional;

        _statusStrip.Items.Add(_statusLabel);
        Controls.Add(_statusStrip);
    }

    public void UpdateStatus(string text)
    {
        _statusLabel.Text = text;
        NativeHelpers.UpdateWindow(Handle);
    }
}

/// <summary>
/// Custom editor that uses a drop-down to pick MaxItems values.
/// </summary>
internal class MaxItemsEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext? context)
        => UITypeEditorEditStyle.DropDown;

    public override object? EditValue(
        ITypeDescriptorContext? context,
        IServiceProvider? provider,
        object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService is null)
            return value;

        var listBox = new ListBox();
        listBox.Items.AddRange(new object[] { 5, 10, 25, 50, 100 });
        listBox.SelectedItem = value;
        listBox.Click += (_, _) => editorService.CloseDropDown();

        // .NET 9: DropDownControl(null) now throws ArgumentNullException.
        // Guard against null controls before calling.
        if (listBox is not null)
            editorService.DropDownControl(listBox);

        return listBox.SelectedItem ?? value;
    }
}

